'use client';

import { useState, useEffect, useCallback } from 'react';
import { 
  CreditCard, 
  Search, 
  Printer, 
  Clock, 
  Check, 
  Settings, 
  AlertCircle,
  FileSpreadsheet,
  CalendarDays,
  IndianRupee,
  ChevronDown
} from 'lucide-react';
import { useStore } from '@/store/useStore';
import { apiClient } from '@/lib/api-client';
import PayslipModal from '@/components/payroll/PayslipModal';

interface PayrollRecord {
  id: string;
  baseSalary: number;
  allowances: number;
  bonus: number;
  deductions: number;
  tax: number;
  netSalary: number;
  payrollMonth: string;
  paymentStatus: 'PAID' | 'PENDING' | 'FAILED';
  employee: {
    id: string;
    employeeCode: string;
    firstName: string;
    lastName: string;
    email: string;
    salary: number;
    department: { name: string } | null;
    designation: { title: string } | null;
  };
}

export default function PayrollPage() {
  const { user } = useStore();
  const [payrolls, setPayrolls] = useState<PayrollRecord[]>([]);
  const [loading, setLoading] = useState(true);
  const [processing, setProcessing] = useState(false);
  const [month, setMonth] = useState('2026-05'); // Default active month

  // Modal previews
  const [isPreviewOpen, setIsPreviewOpen] = useState(false);
  const [selectedPayslipData, setSelectedPayslipData] = useState<any | null>(null);

  const fetchPayrolls = useCallback(() => {
    setLoading(true);
    apiClient.get('/api/payroll', { month })
      .then(res => {
        if (res.success) {
          // If the user is an employee, filter list to only show their own payroll
          if (user?.role === 'EMPLOYEE' && user.employeeId) {
            setPayrolls(res.data.filter((p: PayrollRecord) => p.employee.id === user.employeeId));
          } else {
            setPayrolls(res.data);
          }
        }
      })
      .catch(err => console.error(err))
      .finally(() => setLoading(false));
  }, [month, user]);

  useEffect(() => {
    fetchPayrolls();
  }, [fetchPayrolls]);

  const handleProcessPayroll = async () => {
    if (!confirm(`Run monthly payroll process calculations for ${month}?`)) return;
    
    setProcessing(true);
    try {
      const res = await apiClient.post('/api/payroll/process', { month });
      if (res.success) {
        fetchPayrolls();
      }
    } catch (err) {
      console.error(err);
    } finally {
      setProcessing(false);
    }
  };

  const handleUpdateStatus = async (payrollId: string, status: 'PAID' | 'PENDING' | 'FAILED') => {
    try {
      const res = await apiClient.put('/api/payroll/status', { payrollId, status });
      if (res.success) {
        fetchPayrolls();
      }
    } catch (err) {
      console.error(err);
    }
  };

  const handleOpenPayslip = (record: PayrollRecord) => {
    const monthName = new Date(`${record.payrollMonth}-01`).toLocaleString('en-US', { month: 'long' });
    const yearVal = record.payrollMonth.split('-')[0];
    
    setSelectedPayslipData({
      employeeCode: record.employee.employeeCode,
      name: `${record.employee.firstName} ${record.employee.lastName}`,
      department: record.employee.department?.name || 'Unassigned',
      designation: record.employee.designation?.title || 'Unassigned',
      month: monthName,
      year: yearVal,
      salary: record.employee.salary,
      basic: record.baseSalary,
      allowances: record.allowances,
      bonus: record.bonus,
      deductions: record.deductions,
      tax: record.tax,
      netSalary: record.netSalary,
      paymentStatus: record.paymentStatus,
    });
    setIsPreviewOpen(true);
  };

  const formatCurrency = (val: number) => {
    return new Intl.NumberFormat('en-IN', {
      style: 'currency',
      currency: 'INR',
      maximumFractionDigits: 0,
    }).format(val);
  };

  const isAdminOrHR = user?.role === 'ADMIN' || user?.role === 'HR';

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4">
        <div>
          <h2 className="text-xl font-black text-[var(--text-primary)]">Payroll Logs</h2>
          <p className="text-xs text-[var(--text-muted)] mt-0.5">Manage and generate monthly payslips, taxes, and net disbursements</p>
        </div>

        {isAdminOrHR && (
          <button
            onClick={handleProcessPayroll}
            disabled={processing}
            className="inline-flex items-center justify-center gap-2 rounded-xl bg-blue-600 hover:bg-blue-500 px-4 py-2.5 text-xs font-bold text-white shadow-md shadow-blue-600/10 active:scale-99 transition-all disabled:opacity-50 cursor-pointer"
          >
            {processing ? (
              <div className="h-4 w-4 animate-spin rounded-full border-2 border-white border-t-transparent"></div>
            ) : (
              <FileSpreadsheet size={16} />
            )}
            Process Monthly Payroll
          </button>
        )}
      </div>

      {/* Query Selector Filter Row */}
      <div className="glass-card p-4 flex gap-4 items-center justify-between">
        <div className="flex items-center gap-2">
          <CalendarDays size={16} className="text-blue-500" />
          <span className="font-bold text-xs text-[var(--text-primary)]">Select Payroll Month</span>
        </div>

        <div className="flex gap-2">
          <select 
            value={month} 
            onChange={(e) => setMonth(e.target.value)}
            className="h-9 px-3 rounded-xl border border-[var(--card-border)] bg-[var(--card-bg)] text-xs text-[var(--text-primary)] focus:outline-none focus:border-blue-500"
          >
            <option value="2025-12">Dec 2025</option>
            <option value="2026-01">Jan 2026</option>
            <option value="2026-02">Feb 2026</option>
            <option value="2026-03">Mar 2026</option>
            <option value="2026-04">Apr 2026</option>
            <option value="2026-05">May 2026</option>
          </select>
        </div>
      </div>

      {/* Processed Payroll list table */}
      <div className="glass-card overflow-hidden">
        <div className="overflow-x-auto">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="border-b border-[var(--card-border)] bg-slate-50/50 dark:bg-slate-900/10">
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Employee</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Basic</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Allowances</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Bonus</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Deductions</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Net Pay</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider">Status</th>
                <th className="px-6 py-3.5 text-[10px] font-bold text-[var(--text-muted)] uppercase tracking-wider text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-[var(--card-border)]">
              {loading ? (
                <tr>
                  <td colSpan={8} className="px-6 py-12 text-center text-xs text-[var(--text-muted)]">
                    <div className="flex flex-col items-center justify-center gap-2">
                      <div className="h-6 w-6 animate-spin rounded-full border-2 border-blue-200 border-t-blue-600"></div>
                      <span>Loading payroll runs...</span>
                    </div>
                  </td>
                </tr>
              ) : payrolls.length === 0 ? (
                <tr>
                  <td colSpan={8} className="px-6 py-12 text-center text-xs text-[var(--text-muted)] font-medium">
                    No payroll calculations processed for this month.
                  </td>
                </tr>
              ) : (
                payrolls.map((rec) => (
                  <tr key={rec.id} className="hover:bg-slate-50/50 dark:hover:bg-slate-900/10 transition-colors">
                    <td className="px-6 py-4">
                      <div className="flex items-center gap-3">
                        <div className="flex h-8 w-8 items-center justify-center rounded-lg bg-blue-50 dark:bg-blue-950 text-blue-600 text-xs font-bold uppercase shrink-0">
                          {rec.employee.firstName[0]}{rec.employee.lastName[0]}
                        </div>
                        <div>
                          <p className="text-xs font-bold text-[var(--text-primary)]">{rec.employee.firstName} {rec.employee.lastName}</p>
                          <p className="text-[10px] text-[var(--text-muted)] mt-0.5">{rec.employee.employeeCode}</p>
                        </div>
                      </div>
                    </td>
                    <td className="px-6 py-4 text-xs font-semibold text-[var(--text-primary)]">
                      {formatCurrency(rec.baseSalary)}
                    </td>
                    <td className="px-6 py-4 text-xs font-semibold text-[var(--text-primary)]">
                      {formatCurrency(rec.allowances)}
                    </td>
                    <td className="px-6 py-4 text-xs font-semibold text-[var(--text-primary)]">
                      {formatCurrency(rec.bonus)}
                    </td>
                    <td className="px-6 py-4 text-xs font-semibold text-red-600 dark:text-red-400">
                      {formatCurrency(rec.deductions)}
                    </td>
                    <td className="px-6 py-4 text-xs font-black text-blue-600 dark:text-blue-400">
                      {formatCurrency(rec.netSalary)}
                    </td>
                    <td className="px-6 py-4">
                      <span 
                        className={`inline-flex items-center rounded-full px-2 py-0.5 text-[10px] font-semibold border
                          ${rec.paymentStatus === 'PAID' 
                            ? 'bg-emerald-50 dark:bg-emerald-950/20 text-emerald-600 dark:text-emerald-400 border-emerald-100 dark:border-emerald-900/10' 
                            : rec.paymentStatus === 'PENDING'
                            ? 'bg-amber-50 dark:bg-amber-950/20 text-amber-600 dark:text-amber-400 border-amber-100 dark:border-amber-900/10'
                            : 'bg-red-50 dark:bg-red-950/20 text-red-600 dark:text-red-400 border-red-100 dark:border-red-900/10'
                          }
                        `}
                      >
                        {rec.paymentStatus}
                      </span>
                    </td>
                    <td className="px-6 py-4 text-right">
                      <div className="flex justify-end gap-2">
                        {/* Open Payslip Preview */}
                        <button
                          onClick={() => handleOpenPayslip(rec)}
                          className="px-3 py-1.5 rounded-lg border border-[var(--card-border)] bg-[var(--card-bg)] hover:bg-[var(--primary-light)] text-[var(--text-secondary)] hover:text-blue-600 font-bold text-[10px] transition-colors cursor-pointer"
                        >
                          View Payslip
                        </button>
                        
                        {/* Update Payment status (if Admin/HR) */}
                        {isAdminOrHR && rec.paymentStatus === 'PENDING' && (
                          <button
                            onClick={() => handleUpdateStatus(rec.id, 'PAID')}
                            className="p-1.5 rounded-lg border border-emerald-200 dark:border-emerald-900/20 hover:bg-emerald-600 dark:hover:bg-emerald-500 text-emerald-600 hover:text-white dark:hover:text-white transition-colors cursor-pointer"
                            title="Mark as Paid"
                          >
                            <Check size={13} />
                          </button>
                        )}
                      </div>
                    </td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      {/* Render the Payslip preview/print modal */}
      <PayslipModal 
        isOpen={isPreviewOpen}
        onClose={() => setIsPreviewOpen(false)}
        data={selectedPayslipData}
      />
    </div>
  );
}
